const event = $('Execute Workflow Trigger').item.json;
const wip_rows = $input.all().map(item => item.json).filter(r => r && r.miembro_nombre);
const wip_stats = wip_rows.length > 0
  ? JSON.stringify(wip_rows)
  : 'No hay tareas activas registradas en estado_tareas.';

return [{
  json: {
    correlation_id: event.correlation_id || `risk-${Date.now()}`,
    event_type: event.event_type || 'workload_check',
    actor: event.actor || 'system',
    payload: typeof event.payload === 'string' ? event.payload : JSON.stringify(event.payload || {}),
    wip_stats,
    has_data: wip_rows.length > 0
  }
}];

const rawInput = $json.text ?? $json.output ?? $json.response ?? $json.result ?? $json;
let content = typeof rawInput === 'string' ? rawInput : JSON.stringify(rawInput || {});
content = content.replace(/```json/gi, '').replace(/```/g, '').trim();
const firstBrace = content.indexOf('{');
const lastBrace = content.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) content = content.slice(firstBrace, lastBrace + 1);

let parsed;
try {
  parsed = JSON.parse(content);
} catch (error) {
  parsed = {
    analysis: `No se pudo parsear la respuesta del modelo como JSON válido. Respuesta original: ${content}`,
    risk_level: 'medium',
    recommendation: 'Revisar manualmente la salida del Risk Analyst y ajustar el prompt o parser si se repite.',
    requires_human_approval: true,
    parse_error: error.message
  };
}

const ctx = $('Prepare Risk Context').item.json;
const riskLevel = String(parsed.risk_level || 'medium').toLowerCase();
const risk = ['low', 'medium', 'high'].includes(riskLevel) ? riskLevel : 'medium';

return [{
  json: {
    correlation_id: ctx.correlation_id,
    agent_role: 'Risk Analyst & Workload Balancer',
    decision_type: 'risk_workload',
    input_summary: `Risk/workload analysis for ${ctx.event_type}`,
    context_used: {
      event_type: ctx.event_type,
      actor: ctx.actor,
      payload: ctx.payload,
      wip_stats: ctx.wip_stats,
      has_data: ctx.has_data
    },
    evidence: {
      model_output: parsed,
      parse_error: parsed.parse_error || null
    },
    decision: {
      analysis: parsed.analysis || 'Sin análisis generado por el modelo.',
      workload_action: parsed.workload_action || null
    },
    recommendation: parsed.recommendation || 'Revisar manualmente la carga de trabajo antes de tomar decisiones.',
    confidence: parsed.confidence || 0.8,
    risk_level: risk,
    requires_human_approval: Boolean(parsed.requires_human_approval || risk === 'high')
  }
}];
